  1→import type { PointEvent, UserProfile } from "../../../shared/types.js";
  2→import { isStorageUnavailableError } from "../db.js";
  3→import { edgeConfigStore } from "./edgeConfigStore.js";
  4→import { edgeFallbackStore } from "./edgeFallbackStore.js";
  5→import { postgresStore, getUserProfilesBatch as postgresGetUserProfilesBatch } from "./postgresStore.js";
  6→import type { StorageStore } from "./types.js";
  7→
  8→type StorageDriver = "postgres" | "edge";
  9→
 10→function resolveDriver(): StorageDriver {
 11→  const configured = process.env.DATA_STORE_DRIVER?.trim().toLowerCase();
 12→  if (configured === "edge") return "edge";
 13→  if (configured === "postgres") return "postgres";
 14→  if (process.env.POSTGRES_URL || process.env.POSTGRES_PRISMA_URL || process.env.POSTGRES_URL_NON_POOLING) {
 15→    return "postgres";
 16→  }
 17→  return "edge";
 18→}
 19→
 20→function fallbackEnabled(): boolean {
 21→  return process.env.DATA_READ_FALLBACK_EDGE === "true";
 22→}
 23→
 24→function getPrimaryStore(): StorageStore {
 25→  return resolveDriver() === "postgres" ? postgresStore : edgeConfigStore;
 26→}
 27→
 28→function shouldUseFallback(): boolean {
 29→  return resolveDriver() === "postgres" && fallbackEnabled();
 30→}
 31→
 32→function mergeEvents(primaryEvents: PointEvent[], fallbackEvents: PointEvent[]): PointEvent[] {
 33→  if (!fallbackEvents.length) return primaryEvents;
 34→  if (!primaryEvents.length) return fallbackEvents;
 35→
 36→  const deduped = new Map<string, PointEvent>();
 37→  for (const event of primaryEvents) deduped.set(event.id, event);
 38→  for (const event of fallbackEvents) {
 39→    if (!deduped.has(event.id)) deduped.set(event.id, event);
 40→  }
 41→
 42→  return Array.from(deduped.values()).sort((a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime());
 43→}
 44→
 45→export async function getUserProfile(userId: string): Promise<UserProfile | null> {
 46→  const primary = getPrimaryStore();
 47→  const primaryProfile = await primary.getUserProfile(userId);
 48→  if (primaryProfile || !shouldUseFallback()) return primaryProfile;
 49→  return await edgeFallbackStore.getUserProfile(userId);
 50→}
 51→
 52→export async function upsertUserProfile(userId: string, profile: UserProfile): Promise<void> {
 53→  const primary = getPrimaryStore();
 54→  await primary.upsertUserProfile(userId, profile);
 55→}
 56→
 57→export async function getPointEvents(): Promise<PointEvent[]> {
 58→  const primary = getPrimaryStore();
 59→  const primaryEvents = await primary.getPointEvents();
 60→  if (!shouldUseFallback()) return primaryEvents;
 61→  const fallbackEvents = await edgeFallbackStore.getPointEvents();
 62→  return mergeEvents(primaryEvents, fallbackEvents);
 63→}
 64→
 65→export async function insertPointEvent(event: PointEvent): Promise<void> {
 66→  const primary = getPrimaryStore();
 67→  await primary.insertPointEvent(event);
 68→}
 69→
 70→export async function deletePointEvent(eventId: string): Promise<boolean> {
 71→  const primary = getPrimaryStore();
 72→  return await primary.deletePointEvent(eventId);
