 90→export { isStorageUnavailableError };
 91→
 92→export async function getUserProfilesBatch(ids: string[]): Promise<Map<string, UserProfile>> {
 93→  if (resolveDriver() === "postgres") {
 94→    return await postgresGetUserProfilesBatch(ids);
 95→  }
 96→  // Fallback: fetch individually for non-postgres drivers.
 97→  const entries = await Promise.all(
 98→    ids.map(async (id) => [id, await getUserProfile(id)] as const),
 99→  );
100→  const map = new Map<string, UserProfile>();
101→  for (const [id, profile] of entries) {
102→    if (profile) map.set(id, profile);
103→  }
104→  return map;
105→}
