280→function shouldRunFallbackFraudCheck(event: PointEvent, fraudCheck: SubmissionFraudCheck | null): boolean {
281→  const primaryUrl = typeof event.photoUrl === "string" ? event.photoUrl.trim() : "";
282→  const secondaryUrl = getSecondaryPhotoUrl(event);
283→  if (!fraudCheck) return Boolean(primaryUrl || secondaryUrl);
284→  if (primaryUrl && isPhotoMetadataEffectivelyEmpty(fraudCheck.primaryPhoto)) return true;
285→  if (secondaryUrl && isPhotoMetadataEffectivelyEmpty(fraudCheck.secondaryPhoto)) return true;
286→  return false;
287→}
288→
289→function mergePhotoFraudMetadata(
290→  existing: SubmissionFraudCheck["primaryPhoto"],
291→  recovered: SubmissionFraudCheck["primaryPhoto"],
292→  hasPhotoUrl: boolean,
293→): SubmissionFraudCheck["primaryPhoto"] {
294→  if (!hasPhotoUrl) return existing ?? null;
295→  if (existing && !isPhotoMetadataEffectivelyEmpty(existing)) return existing;
296→  if (recovered) return recovered;
297→  return existing ?? null;
298→}
