 56→  const [categoryData, setCategoryData] = useState<Array<{ name: string; value: number; color: string }>>([]);
 57→  const [heatmap, setHeatmap] = useState<HeatLevel[][]>([
 58→    ['Low', 'Low', 'Low', 'Low'],
 59→    ['Low', 'Low', 'Low', 'Low'],
 60→    ['Low', 'Low', 'Low', 'Low']
 61→  ]);
 62→  const t = (en: string, fr: string) => (language === 'fr' ? fr : en);
 63→
 64→  const categorylabel = (category: SubmissionCategory): string => {
 65→    return categoryPluralLabel(category, language);
