219→      <div className="sticky top-0 z-30 bg-white border-b border-gray-100 px-4 h-14 flex items-center justify-between">
220→        <button onClick={onBack} className="p-2 -ml-2 text-gray-700 hover:text-[#0f2b46] transition-colors">
221→          <ArrowLeft size={20} />
222→        </button>
223→        <h3 className="text-sm font-bold mx-auto">{adminMode ? t('Investor Analytics', 'Analytique investisseur') : t('Leaderboard', 'Classement')}</h3>
224→        <button className="p-2 text-gray-400 absolute right-2">
225→          <Share2 size={20} />
226→        </button>
227→      </div>
228→
229→      <div className="p-4 space-y-6">
230→        {adminMode ? (
231→          <div className="flex items-center justify-between py-2">
232→            <div className="flex items-center space-x-3">
